		return response.JSONError(c, http.StatusUnauthorized, "missing user context")
	}
	var req holdRequest
	if err := response.BindAndValidate(c, &req, func(r *holdRequest) error {
		if r.PackageID <= 0 || r.HostID <= 0 || r.RoomID <= 0 || r.SlotStart == "" {
