	if err := c.Bind(dst); err != nil {
		return JSONError(c, http.StatusBadRequest, "invalid payload")
	}
	if err := validator(dst); err != nil {
		return JSONError(c, http.StatusBadRequest, err.Error())
	}
	return nil
