func resolveCertPath(envKey, fallback string) string {
	// prefer explicit env value
	v := strings.TrimSpace(os.Getenv(envKey))
	if v == "" {
		v = fallback
	}
	// if the path exists as given, return it
	if fileExists(v) {
		return v
	}
	// try common alternative locations relative to cwd
	name := filepath.Base(v)
	candidates := []string{
		filepath.Join(".", "certs", name),
		filepath.Join("..", "certs", name),
		filepath.Join("backend", "certs", name),
		filepath.Join("repo", "backend", "certs", name),
		filepath.Join("certs", name),
	}
	for _, c := range candidates {
		if fileExists(c) {
			return c
		}
	}
	// fallback to original value (may be absolute or intended for container)
	return v
}

func fileExists(path string) bool {
	if path == "" {
		return false
	}
	if _, err := os.Stat(path); err == nil {
		return true
	}
	return false
}

func getEnv(key, fallback string) string {
	v := os.Getenv(key)
	if v == "" {
		return fallback
	}
	return v
}

func getEnvInt(key string, fallback int) int {
	v := os.Getenv(key)
	if v == "" {
		return fallback
	}
	n, err := strconv.Atoi(v)
	if err != nil {
		return fallback
	}
	return n
}

func getEnvDuration(key string, fallback time.Duration) time.Duration {
	v := os.Getenv(key)
	if v == "" {
		return fallback
	}
	d, err := time.ParseDuration(v)
	if err != nil {
		return fallback
	}
	return d
}

func getEnvBool(key string, fallback bool) bool {
	v := strings.TrimSpace(strings.ToLower(os.Getenv(key)))
	if v == "" {
		return fallback
	}
	return v == "1" || v == "true" || v == "yes" || v == "on"
}

func getEnvCSV(key string, fallback []string) []string {
	v := strings.TrimSpace(os.Getenv(key))
	if v == "" {
		return fallback
	}
	parts := strings.Split(v, ",")
	out := make([]string, 0, len(parts))
	for _, p := range parts {
		s := strings.TrimSpace(p)
		if s != "" {
			out = append(out, s)
		}
	}
	if len(out) == 0 {
		return fallback
	}
	return out
}

func ParseCIDRorIP(v string) (*net.IPNet, error) {
	if ip := net.ParseIP(v); ip != nil {
		if ip.To4() != nil {
			_, net4, _ := net.ParseCIDR(ip.String() + "/32")
			return net4, nil
		}
		_, net6, _ := net.ParseCIDR(ip.String() + "/128")
		return net6, nil
	}
	_, n, err := net.ParseCIDR(v)
	if err != nil {
		return nil, err
	}
	return n, nil
}

func (c Config) ValidateSecurityKeys() error {
	if c.JWTSecret == "" || c.EncryptionKey == "" {
		return fmt.Errorf("security keys must be provided via environment variables")
	}
	// reject obvious development defaults
	if c.JWTSecret == "default-jwt-secret" || c.JWTSecret == "default-jwt-secret-zzz" {
		return fmt.Errorf("jwt secret is set to default insecure value; set JWT_SECRET in environment")
	}
	if len(c.EncryptionKey) < 32 {
		return fmt.Errorf("encryption key too short; ENCRYPTION_KEY must be at least 32 characters")
	}
	return nil
}

